<template><view class="page"><xy-header title="我的账单"/><view class="wrap"><view v-for="bill in bills" :key="bill.paymentNo" class="row"><view><text>{{types[bill.businessType]||bill.businessType}}</text><text class="no">{{bill.paymentNo}}</text><text class="time">{{bill.paidTime||bill.createTime}}</text></view><view><text class="amount">¥{{bill.amount}}</text><text class="status">{{bill.status}}</text></view></view><view v-if="!bills.length" class="empty">暂无账单</view></view></view></template>
<script>import{appRequest,ensureMemberSession,showRequestError}from'../../utils/api';export default{data(){return{bills:[],types:{ORDER:'商城订单',MEMBERSHIP:'会员开卡'}}},onShow(){this.load()},methods:{async load(){try{await ensureMemberSession();this.bills=await appRequest({url:'/app/bills'})}catch(e){showRequestError(e)}}}}</script>
<style scoped>.page{min-height:100vh;background:var(--xy-bg)}.wrap{padding:24rpx}.row{display:flex;justify-content:space-between;margin-bottom:16rpx;padding:26rpx;border-radius:20rpx;background:#fff}.row text{display:block}.no,.time,.status{margin-top:8rpx;color:var(--xy-muted);font-size:21rpx}.amount{color:var(--xy-danger);font-weight:700}.empty{padding:120rpx;text-align:center;color:var(--xy-muted)}</style>
